void update_time_neon_360(int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday)
{
#ifdef ENABLE_FACE_NEON_360
    if (!face_neon_360)
    {
        return;
    }
	lv_img_set_src(face_neon_360_8_281828, face_neon_360_dial_img_8_281828_group[((weekday + 6) / 1) % 7]);
	lv_img_set_src(face_neon_360_9_355147, face_neon_360_dial_img_9_355147_group[(day / 1) % 10]);
	lv_img_set_src(face_neon_360_10_355147, face_neon_360_dial_img_9_355147_group[(day / 10) % 10]);
	lv_img_set_src(face_neon_360_11_355147, face_neon_360_dial_img_9_355147_group[(month / 1) % 10]);
	lv_img_set_src(face_neon_360_12_355147, face_neon_360_dial_img_9_355147_group[(month / 10) % 10]);
	lv_img_set_src(face_neon_360_14_286344, face_neon_360_dial_img_14_286344_group[(minute / 1) % 10]);
	lv_img_set_src(face_neon_360_15_312138, face_neon_360_dial_img_15_312138_group[(minute / 10) % 10]);
	lv_img_set_src(face_neon_360_16_359810, face_neon_360_dial_img_16_359810_group[(hour / 1) % 10]);
	lv_img_set_src(face_neon_360_17_385670, face_neon_360_dial_img_17_385670_group[(hour / 10) % 10]);

#endif
}

void update_weather_neon_360(int temp, int icon)
{
#ifdef ENABLE_FACE_NEON_360
    if (!face_neon_360)
    {
        return;
    }
	lv_img_set_src(face_neon_360_21_18897, face_neon_360_dial_img_weather[icon % 8]);

#endif
}

void update_status_neon_360(int battery, bool connection){
#ifdef ENABLE_FACE_NEON_360
    if (!face_neon_360)
    {
        return;
    }
	lv_img_set_src(face_neon_360_2_1662, face_neon_360_dial_img_2_1662_group[(battery / (100 / 11)) % 11]);
	lv_img_set_src(face_neon_360_3_10729, face_neon_360_dial_img_3_10729_group[(battery / 10) % 10]);
	lv_img_set_src(face_neon_360_4_10729, face_neon_360_dial_img_3_10729_group[(battery / 100) % 10]);
	if (battery < 100)
	{
		lv_obj_add_flag(face_neon_360_4_10729, LV_OBJ_FLAG_HIDDEN);
	} else {
		lv_obj_clear_flag(face_neon_360_4_10729, LV_OBJ_FLAG_HIDDEN);
	}
	lv_img_set_src(face_neon_360_5_10729, face_neon_360_dial_img_3_10729_group[(battery / 1000) % 10]);

#endif
}

