void update_all_neon_360(int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday, 
    int temp, int icon, int battery, bool connection, int steps, int distance, int kcal, int bpm, int oxygen)
{
#ifdef ENABLE_FACE_NEON_360
    update_time_neon_360(second, minute, hour, mode, am, day, month, year, weekday);
    update_weather_neon_360(temp, icon);
    update_status_neon_360(battery, connection);
    update_activity_neon_360(steps, distance, kcal);
    update_health_neon_360(bpm, oxygen);
#endif
}

void update_check_neon_360(lv_obj_t *root, int second, int minute, int hour, bool mode, bool am, int day, int month, int year, int weekday, 
    int temp, int icon, int battery, bool connection, int steps, int distance, int kcal, int bpm, int oxygen)
{
#ifdef ENABLE_FACE_NEON_360
    if (root != face_neon_360)
    {
        return;
    }
    update_time_neon_360(second, minute, hour, mode, am, day, month, year, weekday);
    update_weather_neon_360(temp, icon);
    update_status_neon_360(battery, connection);
    update_activity_neon_360(steps, distance, kcal);
    update_health_neon_360(bpm, oxygen);
#endif
}


